import{_ as s,c as e,o as i,a1 as o}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Gerenciamento de Skills: Consultar Skills Disponíveis | opencode-agent-skills","description":"Aprenda a usar a ferramenta get_available_skills. Localize skills rapidamente através de busca, namespace e filtros, dominando as funcionalidades essenciais de descoberta e gerenciamento de skills.","frontmatter":{"title":"Gerenciamento de Skills: Consultar Skills Disponíveis | opencode-agent-skills","sidebarTitle":"Encontrar Skills Rapidamente","subtitle":"Gerenciamento de Skills: Consultar Skills Disponíveis","description":"Aprenda a usar a ferramenta get_available_skills. Localize skills rapidamente através de busca, namespace e filtros, dominando as funcionalidades essenciais de descoberta e gerenciamento de skills.","tags":["Gerenciamento de Skills","Uso de Ferramentas","Namespace"],"prerequisite":["start-installation"],"order":2},"headers":[],"relativePath":"pt/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md","filePath":"pt/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md"}'),n={name:"pt/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md"};function l(t,a,r,p,d,c){return i(),e("div",null,[...a[0]||(a[0]=[o(`<h1 id="consultar-e-listar-skills-disponiveis" tabindex="-1">Consultar e Listar Skills Disponíveis <a class="header-anchor" href="#consultar-e-listar-skills-disponiveis" aria-label="Permalink to &quot;Consultar e Listar Skills Disponíveis&quot;">​</a></h1><h2 id="o-que-voce-vai-aprender" tabindex="-1">O Que Você Vai Aprender <a class="header-anchor" href="#o-que-voce-vai-aprender" aria-label="Permalink to &quot;O Que Você Vai Aprender&quot;">​</a></h2><ul><li>Usar a ferramenta <code>get_available_skills</code> para listar todas as skills disponíveis</li><li>Filtrar skills específicas através de busca por palavras-chave</li><li>Usar namespaces (como <code>project:skill-name</code>) para localizar skills com precisão</li><li>Identificar a origem das skills e listar scripts executáveis</li></ul><h2 id="o-desafio-que-voce-enfrenta" tabindex="-1">O Desafio Que Você Enfrenta <a class="header-anchor" href="#o-desafio-que-voce-enfrenta" aria-label="Permalink to &quot;O Desafio Que Você Enfrenta&quot;">​</a></h2><p>Você quer usar uma skill, mas não lembra o nome exato. Talvez você saiba que é uma skill do projeto, mas não sabe em qual caminho de descoberta está. Ou talvez você só queira navegar rapidamente pelas skills disponíveis no projeto atual.</p><h2 id="quando-usar-esta-tecnica" tabindex="-1">Quando Usar Esta Técnica <a class="header-anchor" href="#quando-usar-esta-tecnica" aria-label="Permalink to &quot;Quando Usar Esta Técnica&quot;">​</a></h2><ul><li><strong>Explorar novos projetos</strong>: Ao entrar em um novo projeto, entenda rapidamente quais skills estão disponíveis</li><li><strong>Nome da skill incerto</strong>: Lembre-se apenas de parte do nome ou da descrição da skill, e precisa de correspondência aproximada</li><li><strong>Conflitos de namespace</strong>: Skills com o mesmo nome no nível do projeto e do usuário, e você precisa especificar qual usar</li><li><strong>Encontrar scripts</strong>: Quer saber quais scripts de automação executáveis estão disponíveis no diretório da skill</li></ul><h2 id="conceito-principal" tabindex="-1">Conceito Principal <a class="header-anchor" href="#conceito-principal" aria-label="Permalink to &quot;Conceito Principal&quot;">​</a></h2><p>A ferramenta <code>get_available_skills</code> ajuda você a ver todas as skills disponíveis na sessão atual. O plugin varre automaticamente as skills de 6 caminhos de descoberta:</p><div class="info custom-block"><p class="custom-block-title">Prioridade de Descoberta de Skills</p><ol><li><code>.opencode/skills/</code> (OpenCode nível de projeto)</li><li><code>.claude/skills/</code> (Claude nível de projeto)</li><li><code>~/.config/opencode/skills/</code> (OpenCode nível de usuário)</li><li><code>~/.claude/skills/</code> (Claude nível de usuário)</li><li><code>~/.claude/plugins/cache/</code> (cache de plugins)</li><li><code>~/.claude/plugins/marketplaces/</code> (plugins instalados)</li></ol></div><p>Skills com o mesmo nome são deduplicadas mantendo apenas a primeira, as subsequentes são ignoradas.</p><p>As informações retornadas pela ferramenta incluem:</p><ul><li><strong>Nome da skill</strong></li><li><strong>Etiqueta de origem</strong> (project, user, claude-project, etc.)</li><li><strong>Descrição</strong></li><li><strong>Lista de scripts executáveis</strong> (se houver)</li></ul><div class="tip custom-block"><p class="custom-block-title">Sintaxe de Namespace</p><p>Você pode especificar explicitamente a origem usando o formato <code>namespace:skill-name</code>:</p><ul><li><code>project:my-skill</code> - usa skill OpenCode nível de projeto (<code>.opencode/skills/</code>)</li><li><code>claude-project:my-skill</code> - usa skill Claude nível de projeto (<code>.claude/skills/</code>)</li><li><code>user:my-skill</code> - usa skill OpenCode nível de usuário (<code>~/.config/opencode/skills/</code>)</li><li><code>claude-user:my-skill</code> - usa skill Claude nível de usuário (<code>~/.claude/skills/</code>)</li><li><code>claude-plugins:my-skill</code> - usa skill de plugins Claude</li></ul></div><h2 id="siga-o-passo-a-passo" tabindex="-1">Siga o Passo a Passo <a class="header-anchor" href="#siga-o-passo-a-passo" aria-label="Permalink to &quot;Siga o Passo a Passo&quot;">​</a></h2><h3 id="etapa-1-listar-todas-as-skills-disponiveis" tabindex="-1">Etapa 1: Listar Todas as Skills Disponíveis <a class="header-anchor" href="#etapa-1-listar-todas-as-skills-disponiveis" aria-label="Permalink to &quot;Etapa 1: Listar Todas as Skills Disponíveis&quot;">​</a></h3><p>No OpenCode, peça ao AI para listar as skills:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrada do usuário:</span></span>
<span class="line"><span>Liste todas as skills disponíveis</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Resposta do sistema:</span></span>
<span class="line"><span>skill-helper (project)</span></span>
<span class="line"><span>  Assistente de operações Git e gerenciamento de branches [scripts: tools/branch.sh, tools/commit.sh]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>test-helper (user)</span></span>
<span class="line"><span>  Ferramenta de teste unitário e análise de cobertura</span></span>
<span class="line"><span></span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Guia de containerização Docker e implantação [scripts: build.sh, deploy.sh]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>claude-code-superpowers (claude-plugins)</span></span>
<span class="line"><span>  Fluxo completo de desenvolvimento de software</span></span></code></pre></div><p><strong>Você deve ver</strong>: uma lista de skills mostrando nome, etiqueta de origem, descrição e lista de scripts.</p><h3 id="etapa-2-usar-busca-para-filtrar" tabindex="-1">Etapa 2: Usar Busca para Filtrar <a class="header-anchor" href="#etapa-2-usar-busca-para-filtrar" aria-label="Permalink to &quot;Etapa 2: Usar Busca para Filtrar&quot;">​</a></h3><p>Se você lembra apenas de parte do nome da skill:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrada do usuário:</span></span>
<span class="line"><span>Encontre skills que contenham &quot;docker&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Resposta do sistema:</span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Guia de containerização Docker e implantação [scripts: build.sh, deploy.sh]</span></span></code></pre></div><p>A busca corresponde palavras-chave no nome e descrição da skill, suportando curingas <code>*</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrada do usuário:</span></span>
<span class="line"><span>Encontre skills que começam com &quot;test&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Resposta do sistema:</span></span>
<span class="line"><span>test-helper (user)</span></span>
<span class="line"><span>  Ferramenta de teste unitário e análise de cobertura</span></span></code></pre></div><p><strong>Você deve ver</strong>: apenas skills correspondentes aos critérios de busca.</p><h3 id="etapa-3-experimentar-sugestoes-de-correspondencia-aproximada" tabindex="-1">Etapa 3: Experimentar Sugestões de Correspondência Aproximada <a class="header-anchor" href="#etapa-3-experimentar-sugestoes-de-correspondencia-aproximada" aria-label="Permalink to &quot;Etapa 3: Experimentar Sugestões de Correspondência Aproximada&quot;">​</a></h3><p>Se você digitar o nome da skill incorretamente:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrada do usuário:</span></span>
<span class="line"><span>Quero usar docker-asistant</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Resposta do sistema:</span></span>
<span class="line"><span>Nenhuma skill encontrada correspondendo a &quot;docker-asistant&quot;. Você quis dizer &quot;docker-helper&quot;?</span></span></code></pre></div><p>O plugin calcula a similaridade baseada na distância de Levenshtein, sugerindo automaticamente o nome de skill mais próximo.</p><p><strong>Você deve ver</strong>: mensagem de erro e sugestão de nome correto.</p><h3 id="etapa-4-usar-namespace-para-localizacao-precisa" tabindex="-1">Etapa 4: Usar Namespace para Localização Precisa <a class="header-anchor" href="#etapa-4-usar-namespace-para-localizacao-precisa" aria-label="Permalink to &quot;Etapa 4: Usar Namespace para Localização Precisa&quot;">​</a></h3><p>Suponha que haja uma skill chamada <code>build-helper</code> tanto no nível do projeto quanto do usuário:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrada do usuário:</span></span>
<span class="line"><span>Liste os detalhes de build-helper</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Resposta do sistema:</span></span>
<span class="line"><span>build-helper (project)</span></span>
<span class="line"><span>  Configuração de build específica do projeto e otimização de compilação [scripts: build.sh, optimize.sh]</span></span></code></pre></div><p>Se o usuário quiser a skill de nível de usuário:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrada do usuário:</span></span>
<span class="line"><span>Use user:build-helper</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Resposta do sistema:</span></span>
<span class="line"><span>build-helper (user)</span></span>
<span class="line"><span>  Ferramenta de cadeia de build genérica e configuração de integração contínua [scripts: ci.sh, test.sh]</span></span></code></pre></div><p><strong>Você deve ver</strong>: acessando skills de mesmo nome de diferentes origens através de prefixos de namespace.</p><h3 id="etapa-5-verificar-scripts-executaveis" tabindex="-1">Etapa 5: Verificar Scripts Executáveis <a class="header-anchor" href="#etapa-5-verificar-scripts-executaveis" aria-label="Permalink to &quot;Etapa 5: Verificar Scripts Executáveis&quot;">​</a></h3><p>Veja quais scripts estão disponíveis no diretório da skill:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Entrada do usuário:</span></span>
<span class="line"><span>Quais scripts o docker-helper tem?</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Resposta do sistema:</span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Guia de containerização Docker e implantação [scripts: build.sh, deploy.sh]</span></span></code></pre></div><p>Os scripts são exibidos entre colchetes após o nome da skill, separados por vírgulas. Você pode usar a ferramenta <code>run_skill_script</code> para executar esses scripts.</p><p><strong>Você deve ver</strong>: nome da skill seguido por <code>[scripts: caminho-do-script1, caminho-do-script2, ...]</code>.</p><h2 id="checkpoints-✅" tabindex="-1">Checkpoints ✅ <a class="header-anchor" href="#checkpoints-✅" aria-label="Permalink to &quot;Checkpoints ✅&quot;">​</a></h2><ul><li>[ ] Você consegue listar todas as skills disponíveis?</li><li>[ ] Você consegue filtrar skills específicas usando busca?</li><li>[ ] Você entende o significado das etiquetas de origem (project, user, claude-project, etc.)?</li><li>[ ] Você consegue explicar a função e a sintaxe dos namespaces de skills?</li><li>[ ] Você consegue identificar a lista de scripts executáveis nas informações da skill?</li></ul><h2 id="armadilhas-comuns" tabindex="-1">Armadilhas Comuns <a class="header-anchor" href="#armadilhas-comuns" aria-label="Permalink to &quot;Armadilhas Comuns&quot;">​</a></h2><h3 id="armadilha-1-sobreposicao-de-skills-com-mesmo-nome" tabindex="-1">Armadilha 1: Sobreposição de Skills com Mesmo Nome <a class="header-anchor" href="#armadilha-1-sobreposicao-de-skills-com-mesmo-nome" aria-label="Permalink to &quot;Armadilha 1: Sobreposição de Skills com Mesmo Nome&quot;">​</a></h3><p>Se houver skills com o mesmo nome no nível do projeto e do usuário, você pode ficar confuso sobre por que a skill carregada não é a que você esperava.</p><p><strong>Causa</strong>: As skills são descobertas por prioridade, com o nível do projeto tendo precedência sobre o nível do usuário. Com o mesmo nome, apenas a primeira é mantida.</p><p><strong>Solução</strong>: Use o namespace para especificar explicitamente, como <code>user:my-skill</code> em vez de apenas <code>my-skill</code>.</p><h3 id="armadilha-2-sensibilidade-a-maiusculas-e-minusculas-na-busca" tabindex="-1">Armadilha 2: Sensibilidade a Maiúsculas e Minúsculas na Busca <a class="header-anchor" href="#armadilha-2-sensibilidade-a-maiusculas-e-minusculas-na-busca" aria-label="Permalink to &quot;Armadilha 2: Sensibilidade a Maiúsculas e Minúsculas na Busca&quot;">​</a></h3><p>As consultas de busca usam expressões regulares, mas têm a flag <code>i</code> definida, então não diferenciam maiúsculas de minúsculas.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Estas buscas são equivalentes</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;docker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;DOCKER&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;Docker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h3 id="armadilha-3-escape-de-curingas" tabindex="-1">Armadilha 3: Escape de Curingas <a class="header-anchor" href="#armadilha-3-escape-de-curingas" aria-label="Permalink to &quot;Armadilha 3: Escape de Curingas&quot;">​</a></h3><p>O <code>*</code> na busca é automaticamente convertido para <code>.*</code> na expressão regular, não é necessário escapar manualmente:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Busca skills que começam com &quot;test&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;test*&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Equivalente à expressão regular /test.*/i</span></span></code></pre></div><h2 id="resumo-da-aula" tabindex="-1">Resumo da Aula <a class="header-anchor" href="#resumo-da-aula" aria-label="Permalink to &quot;Resumo da Aula&quot;">​</a></h2><p><code>get_available_skills</code> é a ferramenta para explorar o ecossistema de skills, suportando:</p><ul><li><strong>Listar todas as skills</strong>: Chamada sem parâmetros</li><li><strong>Filtrar por busca</strong>: Através do parâmetro <code>query</code> correspondendo a nomes e descrições</li><li><strong>Namespace</strong>: Use <code>namespace:skill-name</code> para localização precisa</li><li><strong>Sugestões de correspondência aproximada</strong>: Sugestão automática do nome correto quando há erro de digitação</li><li><strong>Lista de scripts</strong>: Exibe scripts de automação executáveis</li></ul><p>O plugin injeta automaticamente a lista de skills no início da sessão, então geralmente você não precisa chamar esta ferramenta manualmente. Mas é útil nos seguintes cenários:</p><ul><li>Quer navegar rapidamente pelas skills disponíveis</li><li>Não lembra o nome exato da skill</li><li>Precisa distinguir skills de mesmo nome de diferentes origens</li><li>Quer ver a lista de scripts de uma skill específica</li></ul><h2 id="proxima-aula" tabindex="-1">Próxima Aula <a class="header-anchor" href="#proxima-aula" aria-label="Permalink to &quot;Próxima Aula&quot;">​</a></h2><blockquote><p>Na próxima aula aprenderemos <strong><a href="./../loading-skills-into-context/">Carregar Skills no Contexto da Sessão</a></strong>.</p><p>Você aprenderá:</p><ul><li>Usar a ferramenta <code>use_skill</code> para carregar skills na sessão atual</li><li>Entender como o conteúdo da skill é injetado no contexto em formato XML</li><li>Dominar o mecanismo de Synthetic Message Injection (injeção de mensagem sintética)</li><li>Entender como as skills permanecem disponíveis após a compressão da sessão</li></ul></blockquote><hr><h2 id="apendice-referencia-do-codigo-fonte" tabindex="-1">Apêndice: Referência do Código Fonte <a class="header-anchor" href="#apendice-referencia-do-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência do Código Fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver a localização do código fonte</strong></summary><blockquote><p>Última atualização: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do Arquivo</th><th>Linhas</th></tr></thead><tbody><tr><td>Definição da ferramenta GetAvailableSkills</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L29-L72" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>29-72</td></tr><tr><td>Função discoverAllSkills</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L240-L263" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>240-263</td></tr><tr><td>Função resolveSkill</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L269-L283" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>269-283</td></tr><tr><td>Função findClosestMatch</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L88-L125" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>88-125</td></tr></tbody></table><p><strong>Tipos Importantes</strong>:</p><ul><li><code>SkillLabel = &quot;project&quot; | &quot;user&quot; | &quot;claude-project&quot; | &quot;claude-user&quot; | &quot;claude-plugins&quot;</code>: enum de etiquetas de origem das skills</li></ul><p><strong>Constantes Importantes</strong>:</p><ul><li>Limite de correspondência aproximada: <code>0.4</code> (<code>utils.ts:124</code>) - não retorna sugestão se a similaridade for inferior a este valor</li></ul><p><strong>Funções Importantes</strong>:</p><ul><li><code>GetAvailableSkills()</code>: retorna lista formatada de skills, suporta filtragem por busca e sugestões de correspondência aproximada</li><li><code>resolveSkill(skillName: string, skillsByName: Map&lt;string, Skill&gt;)</code>: suporta análise de skills no formato <code>namespace:skill-name</code></li><li><code>findClosestMatch(input: string, candidates: string[])</code>: calcula a melhor correspondência baseada em múltiplas estratégias (prefixo, contém, distância de edição)</li></ul><p><strong>Regras de Negócio</strong>:</p><ul><li>Skills com o mesmo nome são deduplicadas mantendo apenas a primeira (<code>skills.ts:258</code>)</li><li>Consultas de busca suportam curingas <code>*</code>, automaticamente convertidos para expressões regulares (<code>tools.ts:43</code>)</li><li>Sugestões de correspondência aproximada só são acionadas quando há parâmetro de consulta e nenhum resultado (<code>tools.ts:49-57</code>)</li></ul></details>`,64)])])}const h=s(n,[["render",l]]);export{m as __pageData,h as default};
